  ('judicial-d35ec6db-moex-00137', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於行政程序法所規定之法規命令，下列敘述何者正確？', '["行政機關得依職權，自行訂定法規命令", "法規命令之訂定，除由行政機關自行草擬者外，亦得由人民或團體提議為之", "行政機關擬訂法規命令時，除有重大公益之需求外，毋庸於政府公報或新聞紙公告", "法規命令具有間接對外之法律效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00138', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '甲為申請低收入戶之補助，而以書面向主管機關詢問應檢附之資料，主管機關函覆甲申請應檢附之資料。 該函覆之法律性質為何？', '["法規命令", "觀念通知", "行政處分", "公法契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00139', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列何者不是一般處分？', '["土地徵收處分", "將行道樹予以移除", "禁止停車標線之劃設", "警察機關對於違法集會遊行所為解散命令"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00140', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於行政處分附款之敘述，下列何者錯誤？', '["行政處分附負擔之附款被撤銷，不影響行政處分之效力", "行政處分之附款無效，行政處分不當然無效", "行政處分附停止條件之附款，該條件具執行力", "行政處分經撤銷後，其附款隨之失效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00141', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '民眾向行政機關申請核發租金補貼，經核定發放補貼後，發現其租賃契約係偽造，該機關撤銷核發補貼之 行政處分時，依法應如何請求返還該租金補貼？', '["向民事法院起訴請求返還", "依行政執行法逕予強制執行", "另行作成書面行政處分命受領人返還", "向行政法院聲請調解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00142', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依行政程序法規定，關於行政契約之效力，下列敘述何者錯誤？', '["行政契約之一部無效者，全部無效。但欠缺該部分，締約雙方亦將締結契約者，其他部分仍為有效", "代替行政處分之行政契約，行政處分應屬無效者，該契約亦屬無效", "代替行政處分之行政契約，行政處分有得撤銷之違法原因，並為締約雙方所明知者，其效力為無效", "行政契約準用民法規定之結果為無效者，其效力仍屬有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00143', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["行政機關原則上得締結行政契約以代替行政處分", "行政機關原則上得以行政處分，命人民履行行政契約上之金錢給付義務，移送行政執行", "不同於行政處分為單方行為，行政契約為雙方行為", "除依性質或法規規定不得締約外，公法上法律關係得以行政契約設定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00144', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '衛生福利部疾病管制署依據世界各國不同之疾病傳染狀況，發布「國際旅遊疫情建議等級」，該建議等級 之性質為何？', '["行政事實行為", "行政規則", "一般處分", "法規命令"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00145', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '依行政程序法規定，關於行政指導之敘述，下列何者錯誤？', '["係指行政機關在其職權範圍內，為實現一定行政目的，以不具法律上強制力之方法，促請特定人為一定 作為或不作為之行為", "行政機關為行政指導時，應注意有關法規規定之目的，不得濫用", "相對人明確拒絕指導時，行政機關仍得繼續為之，但應給予相對人陳述意見之機會", "行政機關對相對人為行政指導時，應明示行政指導之目的、內容及負責指導者等事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00146', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於行政罰之管轄競合，下列敘述何者錯誤？', '["一個違反行政法上義務之行為，數個機關依法均有管轄權者，由處理在先之機關管轄", "一個違反數個行政法上義務之行為而應處罰鍰，數個機關均有管轄權者，由法定罰鍰數額最高之機關管轄", "一個違反數個行政法上義務之行為而應處罰鍰，數個機關均有管轄權者，法定罰鍰相同時由處理在先之 機關管轄", "一個違反數個行政法上義務之行為而應受沒入之處罰者，由處理在先之機關裁處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
